#include <unordered_map>
#include <string>

struct Customer {
    std::string name_;
    const std::string& name() const { return name_; }
};

// Noncompliant: Hash function that can throw exceptions
struct MyHash {
    size_t operator()(Customer c) const {  // Copying may throw
        if (c.name().empty()) {
            throw std::runtime_error("Empty name not allowed");
        }
        return std::hash<std::string>{}(c.name());
    }
};

std::unordered_map<Customer, int, MyHash> customerMap;

