compliant:
#include <unordered_map>
#include <string>

struct Customer {
    std::string name_;
    const std::string& name() const { return name_; }
};

// Compliant: Hash function that doesn't throw exceptions
struct MyHash {
    size_t operator()(const Customer& c) const noexcept {
        // Use reference to avoid copying
        if (c.name().empty()) {
            return 0;  // Return default hash instead of throwing
        }
        return std::hash<std::string>{}(c.name());
    }
};

std::unordered_map<Customer, int, MyHash> customerMap;

// Another compliant example using standard hash
struct GoodHash {
    size_t operator()(const std::string& s) const noexcept {
        // Handle edge cases without throwing
        return s.empty() ? 0 : std::hash<std::string>{}(s);
    }
};
